CREATE TABLE "ACCTITEM_DEF" ("ITEMCODE" VARCHAR2(30), "ITEMNAME" VARCHAR2(64), "ITEMLEVEL" NUMBER(2,0), "PARENTITEMCODE" VARCHAR2(32), "WRTOFF_ORDER" NUMBER(2,0), "SERV_ID" VARCHAR2(12) DEFAULT '0', "SUBSERV_ID" VARCHAR2(12), "IN_USE" NUMBER(1,0), "ITEMCODEN" NUMBER(8,0), "FINANCEITEM_CODE" VARCHAR2(32), "IS_NEW_SERVICE" NUMBER(1,0) DEFAULT 1, "IS_CAL_SCORE" NUMBER(1,0) DEFAULT 1, "MONTH_FEE_PRECHARGE_COUNT" NUMBER(4,0) DEFAULT -1, "IN_PAUSE" NUMBER(1,0) DEFAULT 0, "PAUSE_TIME" DATE, "PAUSE_REASON" VARCHAR2(256), "ADD_REASON" VARCHAR2(256), "ODD_ROUND_TYPE" CHAR(1), "UNIT" NUMBER(2,0) DEFAULT 0) ;

   COMMENT ON COLUMN "ACCTITEM_DEF"."ITEMCODE" IS '帐单项代码';
   COMMENT ON COLUMN "ACCTITEM_DEF"."ITEMNAME" IS '帐单项名称';
   COMMENT ON COLUMN "ACCTITEM_DEF"."ITEMLEVEL" IS '层次';
   COMMENT ON COLUMN "ACCTITEM_DEF"."PARENTITEMCODE" IS '上级帐单项代码';
   COMMENT ON COLUMN "ACCTITEM_DEF"."WRTOFF_ORDER" IS '确省销帐顺序';
   COMMENT ON COLUMN "ACCTITEM_DEF"."SERV_ID" IS '服务';
   COMMENT ON COLUMN "ACCTITEM_DEF"."SUBSERV_ID" IS '子服务';
   COMMENT ON COLUMN "ACCTITEM_DEF"."IN_USE" IS '是否在用';
   COMMENT ON COLUMN "ACCTITEM_DEF"."IN_PAUSE" IS '暂停状态，0:正常 1:暂停';
   COMMENT ON COLUMN "ACCTITEM_DEF"."PAUSE_TIME" IS '暂停时间';
   COMMENT ON COLUMN "ACCTITEM_DEF"."PAUSE_REASON" IS '暂停原因';
   COMMENT ON COLUMN "ACCTITEM_DEF"."ADD_REASON" IS '新增原因';
   COMMENT ON TABLE "ACCTITEM_DEF"  IS '帐单费用代码定义表';



  CREATE TABLE "FEEGROUP_ACCITEM_DEF" ("FEEGROUPID" VARCHAR2(32), "ITEMCODE" VARCHAR2(32), "STARTCYCLE" NUMBER(8,0), "ENDCYCLE" NUMBER(8,0), "PRECEDENCE" NUMBER(4,0), "INCLUDEFLAG" CHAR(1) DEFAULT 1) ;

   COMMENT ON COLUMN "FEEGROUP_ACCITEM_DEF"."INCLUDEFLAG" IS '包含或排除标志，"1"表示包含，"0"表示排除';



  CREATE TABLE "CUSTBILL_CELL_DEF" ("TEMPLATE_ID" NUMBER(10,0), "CELL_ID" VARCHAR2(15), "CELL_NAME" VARCHAR2(64), "SORT_ORDER" NUMBER(5,0), "CELL_TYPE" NUMBER(1,0) DEFAULT 0, "AUTOGETCELLNAME" NUMBER(2,0) DEFAULT 0, "ACCTMATCHTYPE" NUMBER(1,0) DEFAULT 0, "PCELL_ID" VARCHAR2(15), "DISPLAY" NUMBER(1,0) DEFAULT 1, "BILLLEVEL" NUMBER(8,0) DEFAULT 0, "FEELIMIT" NUMBER(4,0) DEFAULT 0, "SELFFLAG" NUMBER(1,0) DEFAULT 0, "PARENTID" VARCHAR2(15), "TRANSZEROFEE" NUMBER(1,0) DEFAULT 0, "AUTOEXPANDLEVEL" NUMBER(1,0) DEFAULT 1, "SELFDEFAULT" NUMBER(1,0) DEFAULT 0, "ACCUMULATETYPE" NUMBER(1,0) DEFAULT 0, "TAXRATE" NUMBER(5,0) DEFAULT 0) ;

   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."ACCTMATCHTYPE" IS '账号匹配关系类型：0，主帐号或非主帐号都可以匹配；1，与主帐号匹配；2，仅与非主帐号才匹配';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."PCELL_ID" IS '父账单项编码';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."DISPLAY" IS '是否显示当前账单项（0－不显示当前账单项，1－显示当前账单项名称及金额，2－只显示当前账单项名称）';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."BILLLEVEL" IS '级别';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."FEELIMIT" IS '0,不限制取值；1：只能取大于0的明细帐单费用；-1:只能取小于0的明细帐单费用';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."SELFFLAG" IS '0：所有业务；1：自有业务；2：代收业务';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."PARENTID" IS 'CELL上级ID';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."TRANSZEROFEE" IS '是否显示，当此条数据金额为0时，是否展示在前台';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."AUTOEXPANDLEVEL" IS '自动扩展级别，为1则显示2级菜单项，为0不显示';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."SELFDEFAULT" IS '自有和代收业务默认处理方式: 0:自有, 1:代收';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."ACCUMULATETYPE" IS '费用汇总方式：0：按配置明细汇总； 1：用下级费用项汇总';
   COMMENT ON COLUMN "CUSTBILL_CELL_DEF"."TAXRATE" IS '税率  11%的税写为1100,范围为0-10000';



  CREATE TABLE "BILLITEM_CELL_DEF" ("TEMPLATE_ID" NUMBER(10,0), "CELL_ID" VARCHAR2(32), "ITEMTYPE" NUMBER(1,0), "ITEMCODE" VARCHAR2(32), "ITEMADDCODE" VARCHAR2(32), "ISWRTOFFED" NUMBER(1,0), "INCL_SUBJECTID" VARCHAR2(256), "EXCL_SUBJECTID" VARCHAR2(256), "EXCL_ITEMCODE" VARCHAR2(256), "COEFFICIENT" NUMBER(2,0) DEFAULT 1, "CELL_TYPE" NUMBER(1,0) DEFAULT 1, "INCLUDEPACKAGE" NUMBER(1,0) DEFAULT 0, "GETNAMEORDER" NUMBER(1,0) DEFAULT 0, "FEEGROUPLIMIT" NUMBER(1,0) DEFAULT 0, "SELFDEFAULT" NUMBER(1,0) DEFAULT -1) ;

   COMMENT ON COLUMN "BILLITEM_CELL_DEF"."COEFFICIENT" IS '其取值范围是1,-1,0';
   COMMENT ON COLUMN "BILLITEM_CELL_DEF"."INCLUDEPACKAGE" IS '是否取套餐：0：所有都取 1 ：只取带@符号的2：只取不带@符号的';
   COMMENT ON COLUMN "BILLITEM_CELL_DEF"."GETNAMEORDER" IS '附加编码的取值顺序：0：取后面一个；1:多个时，取前面一个';
   COMMENT ON COLUMN "BILLITEM_CELL_DEF"."FEEGROUPLIMIT" IS '0:不判断BILLITEM表中FEEGROUP字段  1:此字段必须为0或者空(不包含代他人付费)  2：此字段必须不为0且不为空(只包含代他人付费)';
   COMMENT ON COLUMN "BILLITEM_CELL_DEF"."SELFDEFAULT" IS 'selfflag默认值：-1:不参考本表;0:自有;1:代收';



  CREATE TABLE "CODE_DICT" ("CATALOG" VARCHAR2(32), "CODE" VARCHAR2(32), "NAME" VARCHAR2(128), "NOTE" VARCHAR2(128)) ;

   COMMENT ON COLUMN "CODE_DICT"."CATALOG" IS '分类';
