  CREATE TABLE "TARIFF_ITEM" ("TARIFF_SCHEMA_ID" NUMBER(9,0), "APPLYTIME" DATE, "EXPIRETIME" DATE, "TARIFF_CRITERIA" VARCHAR2(256), "SUBTARIFF_TYPE" NUMBER(1,0), "TARIFF_ID" NUMBER(9,0), "RATIO" NUMBER(5,2), "RATETYPE" CHAR(1), "PARAM_STRING" VARCHAR2(128), "PRECEDENCE" NUMBER(4,0), "EXPR_ID" NUMBER(9,0), "G_PARAM" VARCHAR2(256), "IS_DYNAMIC" NUMBER(1,0) DEFAULT (0), "G_CRITERIA" VARCHAR2(512), "BILLCODE" VARCHAR2(32), "TARIFF_ITEM_SN" VARCHAR2(20) DEFAULT 0, "TARIFF_ITEM_NAME" VARCHAR2(64), "TEMPLATENO" VARCHAR2(32), "USAGE_KEY_INFO" VARCHAR2(500), "G_USAGE_KEY_INFO" VARCHAR2(500), "LEFT_EVAL_FLAG" NUMBER(1,0) DEFAULT 0, "FLAT_RATES_FLAG" NUMBER(2,0) DEFAULT 1) ;

   COMMENT ON COLUMN "TARIFF_ITEM"."TARIFF_SCHEMA_ID" IS '资费模式号';
   COMMENT ON COLUMN "TARIFF_ITEM"."APPLYTIME" IS '生效时间';
   COMMENT ON COLUMN "TARIFF_ITEM"."EXPIRETIME" IS '失效时间';
   COMMENT ON COLUMN "TARIFF_ITEM"."TARIFF_CRITERIA" IS '资费条件';
   COMMENT ON COLUMN "TARIFF_ITEM"."SUBTARIFF_TYPE" IS '下级资费类型，1-费率（CHARGE_RATE），2-资费模式（TARIFF_SCHEMA），3-费用项（FEE）';
   COMMENT ON COLUMN "TARIFF_ITEM"."TARIFF_ID" IS '下级资费号';
   COMMENT ON COLUMN "TARIFF_ITEM"."RATIO" IS '比率';
   COMMENT ON COLUMN "TARIFF_ITEM"."RATETYPE" IS '资费类型';
   COMMENT ON COLUMN "TARIFF_ITEM"."PARAM_STRING" IS '资费参数串';
   COMMENT ON COLUMN "TARIFF_ITEM"."PRECEDENCE" IS '优先级';
   COMMENT ON COLUMN "TARIFF_ITEM"."IS_DYNAMIC" IS '是否动态资费';
   COMMENT ON COLUMN "TARIFF_ITEM"."TARIFF_ITEM_SN" IS '资费模式项序号（生成规则为：YYMMDDHH24MISS+8位序号)';
   COMMENT ON COLUMN "TARIFF_ITEM"."TARIFF_ITEM_NAME" IS '资费模式项名称';
   COMMENT ON COLUMN "TARIFF_ITEM"."TEMPLATENO" IS '短信模板号';
   COMMENT ON COLUMN "TARIFF_ITEM"."LEFT_EVAL_FLAG" IS '剩余量评估标识 0：不评估;1：评估';
   COMMENT ON COLUMN "TARIFF_ITEM"."FLAT_RATES_FLAG" IS '0 平滑费率标记， 2 不可变的不平滑费率标记,1 可变的不平滑费率标记';
   COMMENT ON TABLE "TARIFF_ITEM"  IS '资费模式项';



