  CREATE TABLE "TARIFF_PLAN" ("TARIFF_PLAN_ID" NUMBER(6,0), "TARIFF_PLAN_NAME" VARCHAR2(128), "IS_RECURSIVE" NUMBER(1,0) DEFAULT 0, "PRECEDENCE" NUMBER(9,0), "PROCESS_BEFORE" NUMBER(4,0) DEFAULT 0, "PROCESS_AFTER" NUMBER(4,0) DEFAULT 0, "PLANTYPE" VARCHAR2(4), "NOTE" VARCHAR2(400), "PRECEDENCE_ACCDISC" NUMBER(4,0), "PRICEPLANTYPE" NUMBER(4,0), "REGION" NUMBER(5,0) DEFAULT 0, "HISTORY" VARCHAR2(2048), "MERGE_MODE" NUMBER(1,0) DEFAULT 1, "DYNAMIC_PRECEDENCE" VARCHAR2(200), "G_DYNAMIC_PRECEDENCE" VARCHAR2(400), "CATALOG_TYPE" VARCHAR2(10) DEFAULT '0', "SERVICE_FLAG" VARCHAR2(500), "G_SERVICE_FLAG" VARCHAR2(500), "SUB_DYNAMIC_PRECEDENCE" VARCHAR2(200), "G_SUB_DYNAMIC_PRECEDENCE" VARCHAR2(400), "PHASE_PRECEDENCE" NUMBER(4,0) DEFAULT 0, "TYPE_PRECEDENCE" NUMBER(4,0) DEFAULT 0, "CARRYOVER_ENTITYID" NUMBER(4,0), "CARRYOVER_ATTRID" NUMBER(8,0)) ;

   COMMENT ON COLUMN "TARIFF_PLAN"."TARIFF_PLAN_ID" IS '资费政策标识';
   COMMENT ON COLUMN "TARIFF_PLAN"."TARIFF_PLAN_NAME" IS '资费政策名称';
   COMMENT ON COLUMN "TARIFF_PLAN"."IS_RECURSIVE" IS '可否嵌套调用';
   COMMENT ON COLUMN "TARIFF_PLAN"."PRECEDENCE" IS '优先级';
   COMMENT ON COLUMN "TARIFF_PLAN"."PROCESS_BEFORE" IS '批价前处理方案，参见“process_schema”表';
   COMMENT ON COLUMN "TARIFF_PLAN"."PROCESS_AFTER" IS '批价后处理方案';
   COMMENT ON COLUMN "TARIFF_PLAN"."NOTE" IS '资费政策说明';
   COMMENT ON COLUMN "TARIFF_PLAN"."REGION" IS '地区号，0表示全省';
   COMMENT ON COLUMN "TARIFF_PLAN"."DYNAMIC_PRECEDENCE" IS '动态优先级表达式';
   COMMENT ON TABLE "TARIFF_PLAN"  IS '资费政策表';



  CREATE TABLE "TARIFF_SCHEMA" ("TARIFF_SCHEMA_ID" NUMBER(9,0), "TARIFF_NAME" VARCHAR2(64), "TARIFF_TYPE" NUMBER(2,0), "FIELDCOUNT" NUMBER(4,0), "FIELD_DEF" VARCHAR2(256), "MATCH_ORDER" NUMBER(1,0), "MATCH_TYPE" NUMBER(1,0), "APPLY_METHOD" NUMBER(1,0), "REFID" NUMBER(4,0), "DISCOUNT_FEE_ID" NUMBER(9,0), "G_FIELD_DEF" VARCHAR2(256), "ROUND_METHOD" NUMBER(1,0), "ROUND_SCALE" NUMBER(2,0), "REF_OFFSET" NUMBER(4,0), "EVENT_ID" NUMBER(4,0), "BILLCODE_ORDER" NUMBER(1,0) DEFAULT 0, "CREATETIME" DATE DEFAULT sysdate, "REGION" NUMBER(5,0) DEFAULT 0) ;

   COMMENT ON COLUMN "TARIFF_SCHEMA"."TARIFF_SCHEMA_ID" IS '资费模式号';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."TARIFF_NAME" IS '资费模式名称';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."TARIFF_TYPE" IS '资费模式类型';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."FIELDCOUNT" IS '参数数量';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."FIELD_DEF" IS '参数定义，以“,”号隔开的字段定义';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."MATCH_ORDER" IS '匹配顺序，1-二分匹配，2-从头顺序匹配，3-从尾顺序匹配';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."MATCH_TYPE" IS '匹配方法，1-等长精确匹配，2-不精确匹配';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."APPLY_METHOD" IS '应用时时间判断方法，1-按当前时间，2-按计费事件发送时间，3-忽略时间匹配';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."REFID" IS '标记位置';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."DISCOUNT_FEE_ID" IS '优惠费用标识，参见“FEE”表';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."G_FIELD_DEF" IS '中文参数定义';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."ROUND_METHOD" IS '取整方法，0-不控制精度，1-比例运算前舍入，2-比例运算后舍入';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."ROUND_SCALE" IS '取整精度';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."REF_OFFSET" IS '标记偏移';
   COMMENT ON COLUMN "TARIFF_SCHEMA"."REGION" IS '地区号，0表示全省';
   COMMENT ON TABLE "TARIFF_SCHEMA"  IS '资费模式定义';



  CREATE TABLE "TARIFF_PLAN_ITEM" ("TARIFF_PLAN_ID" NUMBER(6,0), "CALCTYPE" NUMBER(1,0), "FEE_ID" NUMBER(9,0), "TARIFF_SCHEMA_ID" NUMBER(9,0), "CHARGING_EVENT_ID" NUMBER(4,0), "PRECEDENCE" NUMBER(4,0), "APPLYTIME" DATE, "EXPIRETIME" DATE, "APPLY_METHOD" NUMBER(1,0), "DISCOUNT_TYPE" NUMBER(1,0), "BASE_FEE_ID" NUMBER(9,0), "DISCOUNT_FEE_ID" NUMBER(9,0), "CHARGING_COND" VARCHAR2(512), "SWITCH_METHOD" NUMBER(2,0), "SWITCH_UNIT" NUMBER(8,0), "G_CHARGING_COND" VARCHAR2(1024), "BILLCODE" VARCHAR2(32), "SELECT_METHOD" NUMBER(1,0), "TARIFF_PLAN_ITEM_SN" VARCHAR2(20) DEFAULT 0, "TARIFF_PLAN_ITEM_NAME" VARCHAR2(64), "SERV_ID" NUMBER(4,0), "FEE_ROUND_TYPE" NUMBER(1,0) DEFAULT 0, "FEE_ROUND_SCALE" NUMBER(2,0) DEFAULT 2, "CATALOG_TYPE" VARCHAR2(10) DEFAULT '0') ;

   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."TARIFF_PLAN_ID" IS '资费政策标识';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."CALCTYPE" IS '计算类型，1-按实际类型，2-周期性，3-一次性';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."FEE_ID" IS '参见FEE表';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."TARIFF_SCHEMA_ID" IS '资费模式标识';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."CHARGING_EVENT_ID" IS '计费事件标识';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."PRECEDENCE" IS '优先级';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."APPLYTIME" IS '生效时间';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."EXPIRETIME" IS '失效时间';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."APPLY_METHOD" IS '时间应用方式，1-按当前时间匹配，2-按时间发生时间匹配，3-忽略时间匹配';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."DISCOUNT_TYPE" IS '优惠类型';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."BASE_FEE_ID" IS '基准费用标识';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."DISCOUNT_FEE_ID" IS '优惠费用标识';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."CHARGING_COND" IS '计费条件';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."SWITCH_METHOD" IS '切换方式，1-按开始时间，2-跨边界的一个时间单位向前靠，3-跨边界的一个时间单位向后靠，4-跨边界的一个时间单位按比例分配';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."SWITCH_UNIT" IS '切换单位';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."G_CHARGING_COND" IS '中文计费条件';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."SELECT_METHOD" IS '批价原则：1：取较低的费用;2：无条件取本费用;3：有条件取本费用（空值默认为3）';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."TARIFF_PLAN_ITEM_SN" IS '资费政策项序号（生成规则为：YYMMDDHH24MISS+8位序号)';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."TARIFF_PLAN_ITEM_NAME" IS '资费政策项名称';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."SERV_ID" IS '业务ID';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."FEE_ROUND_TYPE" IS '取整类型：0:不控制，1-四舍五入，2-舍掉尾数，3-尾数进位';
   COMMENT ON COLUMN "TARIFF_PLAN_ITEM"."FEE_ROUND_SCALE" IS '取整精度：保留小数位数';
   COMMENT ON TABLE "TARIFF_PLAN_ITEM"  IS '资费政策项';


  CREATE TABLE "BILLINGCYCLE" ("CYCLE_SCHEMA_ID" NUMBER(4,0), "CYCLE_ID" NUMBER(8,0), "CYCLE_NAME" VARCHAR2(64), "CYCLE_STATUS" NUMBER(1,0), "OPENDATE" DATE, "CLOSEDATE" DATE, "INVOICEDATE" DATE) ;




