  CREATE TABLE "AUDIT_LOG" ("LOGNUM" VARCHAR2(24), "OPERATOR" VARCHAR2(16), "LOGTIME" DATE, "TABLENAME" VARCHAR2(64), "MAINTAINTYPE" CHAR(1), "KEYVALUE" VARCHAR2(1024), "COLNAME" VARCHAR2(64), "OLDVALUE" VARCHAR2(4000), "NEWVALUE" VARCHAR2(4000), "AUDIT_STATUS" NUMBER(1,0) DEFAULT 0, "REASON" VARCHAR2(128), "AUDIT_TIME" DATE, "AUDIT_OPERATOR" VARCHAR2(20), "COL_DATATYPE" VARCHAR2(106), "CLIENTINFO" VARCHAR2(1024), "LOGONID" NUMBER(10,0), "LOGONSEQ" VARCHAR2(32), "OPERNUM" VARCHAR2(24))  PARTITION BY RANGE ("LOGTIME")  (PARTITION "P_202004"  VALUES LESS THAN (TO_DATE(' 2020-05-01 00:00:00', 'SYYYY-MM-DD HH24:MI:SS', 'NLS_CALENDAR=GREGORIAN')) , PARTITION "P_202005"  VALUES LESS THAN (TO_DATE(' 2020-06-01 00:00:00', 'SYYYY-MM-DD HH24:MI:SS', 'NLS_CALENDAR=GREGORIAN')) , PARTITION "P_202006"  VALUES LESS THAN (TO_DATE(' 2020-07-01 00:00:00', 'SYYYY-MM-DD HH24:MI:SS', 'NLS_CALENDAR=GREGORIAN')) , PARTITION "P_MAX"  VALUES LESS THAN (MAXVALUE) ) ;





  CREATE TABLE "ENTITY_ATTR_DEF" ("ENTITY_ID" NUMBER(4,0), "ATTR_ID" NUMBER(8,0), "ATTR_NAME" VARCHAR2(32), "ATTR_TYPE" NUMBER(1,0), "MULTIVALUE" NUMBER(1,0), "ISUNIQUE" NUMBER(1,0), "ISRESIDENT" NUMBER(1,0), "ATTR_CLASS" NUMBER(3,0), "DATATYPE" NUMBER(1,0), "LENGTH" NUMBER(4,0), "SCALE" NUMBER(1,0), "EXPIRE_DAYS" NUMBER(6,0), "SERVICE_TYPE" VARCHAR2(32), "UNIT" VARCHAR2(32), "FIXEDFEE_FLAG" NUMBER(1,0) DEFAULT 0, "TABLE_NAME" VARCHAR2(32), "INC_APPSYSLIST" VARCHAR2(64), "EXC_APPSYSLIST" VARCHAR2(64), "ABM_RESOURCE_ID" NUMBER(10,0) DEFAULT 0, "ROUND_TYPE" CHAR(1) DEFAULT 'D', "ROUND_UNIT" NUMBER(10,0) DEFAULT 0, "BASE_UNIT" NUMBER(10,0) DEFAULT 0, "IS_RECORD_OVER_USAGE" CHAR(1) DEFAULT 'T', "ATTR_ADD_CODE_DEF" VARCHAR2(50), "VALID_CYCLE_COUNT" NUMBER(8,0) DEFAULT 0, "VALID_CYCLE_UNIT" NUMBER(1,0) DEFAULT 1, "CYCLE_ATTR_ID" NUMBER(4,0) DEFAULT 0, "NEED_NOTIFY_DETAIL" NUMBER(1,0) DEFAULT 0, "IS_BIND_PRODUCT_INST" NUMBER(1,0) DEFAULT 0, "BIND_PRODUCT_ELEMENT_CODE" VARCHAR2(60), "MERGE_TYPE" NUMBER(1,0) DEFAULT 0, "CARRYOVER_FLAG" NUMBER(1,0) DEFAULT 0, "SHARED_MODE" NUMBER(2,0) DEFAULT -1, "SHARED_MODE_SYNC_FLAG" NUMBER(1,0) DEFAULT 1, "ADDCODE_DEAL_TYPE" NUMBER(1,0) DEFAULT 0) ;

   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ENTITY_ID" IS '实体ID';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ATTR_ID" IS '属性号';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ATTR_NAME" IS '属性名称';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ATTR_TYPE" IS '属性类型';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."MULTIVALUE" IS '是否多值属性';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ISUNIQUE" IS '是否唯一';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ISRESIDENT" IS '是否装载内存';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."ATTR_CLASS" IS '属性类别';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."DATATYPE" IS '数据类型';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."LENGTH" IS '长度';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."SCALE" IS '精度';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."FIXEDFEE_FLAG" IS 'related to fixed fee calculation flag';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."IS_RECORD_OVER_USAGE" IS '是否记录超出量';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."IS_BIND_PRODUCT_INST" IS '鏄惁缁戝畾浜у搧瀹炰緥 1:鐪?0:鍋?缂虹渷鍊?0';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."BIND_PRODUCT_ELEMENT_CODE" IS '绑定产品元素编码';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."MERGE_TYPE" IS '合并类型,只针对赠送量属性有效;0(默认)--不合并,1--匹配合并';
   COMMENT ON COLUMN "ENTITY_ATTR_DEF"."SHARED_MODE" IS '-1 兼容原来，0 非共享 ，1-99 流量池共享';
