   COMMENT ON COLUMN "DATAFILE"."SORT" IS '文件选择顺序';
   COMMENT ON TABLE "DATAFILE"  IS '原始数据文件处理定义';




  CREATE TABLE "CPCONFIG" ("NODE" VARCHAR2(16), "ID" VARCHAR2(16), "DESCRIPTION" VARCHAR2(164), "OPERATION_TYPE" VARCHAR2(1), "GATHER_MODE" VARCHAR2(16), "HOSTIP_PAIR" VARCHAR2(33), "USER_PAIR" VARCHAR2(33), "PASSWORD_PAIR" VARCHAR2(65), "ENCRYPTION" NUMBER(1,0), "SOURCE_PATTERN" VARCHAR2(64), "SOURCE_NAME_FILTER" VARCHAR2(64), "SOURCE_MOVEDEL" NUMBER(1,0), "SOURCE_PATH" VARCHAR2(128), "SOURCE_BACKUP_PATH" VARCHAR2(128), "DEST_PATH" VARCHAR2(128), "DEST_NAME_FORMAT" VARCHAR2(64), "BUSY_TIME" VARCHAR2(11), "BUSY_INTERVAL" NUMBER(10,0), "FREE_INTERVAL" NUMBER(10,0), "NOFILE_LIMIT" NUMBER(10,0), "FILE_ANALYZER" VARCHAR2(64), "SEQUENCE_CONTROL" NUMBER(1,0), "SEQUENCE_SCOPE" VARCHAR2(33), "SEQUENCE_SYNC" NUMBER(1,0), "WARN_MODE" VARCHAR2(16), "RECORD_SIZE" NUMBER(10,0), "FTP_TIMEOUT" NUMBER(10,0), "FTP_RESUME" NUMBER(1,0), "FTP_PASSIVE" NUMBER(1,0), "SIZE_COL" NUMBER(2,0), "EXTRACOPY" NUMBER(2,0), "STATUS" NUMBER(1,0), "LOGTIME" DATE DEFAULT sysdate) ;

   COMMENT ON COLUMN "CPCONFIG"."NODE" IS '主机名称';
   COMMENT ON COLUMN "CPCONFIG"."ID" IS '采集点编号';
   COMMENT ON COLUMN "CPCONFIG"."DESCRIPTION" IS '可选，采集点说明';
   COMMENT ON COLUMN "CPCONFIG"."OPERATION_TYPE" IS '操作类型
G=FTP取 P=FTP送
N=诺基亚 F=FTAM';
   COMMENT ON COLUMN "CPCONFIG"."GATHER_MODE" IS '可选，采集模式，a=保留最新文件';
   COMMENT ON COLUMN "CPCONFIG"."HOSTIP_PAIR" IS '半角逗号分隔的主备IP地址';
   COMMENT ON COLUMN "CPCONFIG"."USER_PAIR" IS '半角逗号分隔的主备用户';
   COMMENT ON COLUMN "CPCONFIG"."PASSWORD_PAIR" IS '半角逗号分隔的主备口令';
   COMMENT ON COLUMN "CPCONFIG"."ENCRYPTION" IS '可选，密码形式，0=明文  1=密文';
   COMMENT ON COLUMN "CPCONFIG"."SOURCE_PATTERN" IS '可选，源名称匹配模式，支持通配符，如：*.dat，b??.dat';
   COMMENT ON COLUMN "CPCONFIG"."SOURCE_NAME_FILTER" IS '可选，源名称正则表达式，进一步过滤文件名称';
   COMMENT ON COLUMN "CPCONFIG"."SOURCE_MOVEDEL" IS '源移删标志，0=无  1=删除  2=移动';
   COMMENT ON COLUMN "CPCONFIG"."SOURCE_PATH" IS '源路径';
   COMMENT ON COLUMN "CPCONFIG"."SOURCE_BACKUP_PATH" IS '可选，源备份路径';
   COMMENT ON COLUMN "CPCONFIG"."DEST_PATH" IS '目的路径';
   COMMENT ON COLUMN "CPCONFIG"."DEST_NAME_FORMAT" IS '可选，目的名称转换格式，%引用日期格式  @=源文件名称';
   COMMENT ON COLUMN "CPCONFIG"."BUSY_TIME" IS '可选，专用忙时时段（hh:mi-hh:mi，24时制）';
   COMMENT ON COLUMN "CPCONFIG"."BUSY_INTERVAL" IS '忙时采集周期（秒）';
   COMMENT ON COLUMN "CPCONFIG"."FREE_INTERVAL" IS '可选，闲时采集周期（秒）';
   COMMENT ON COLUMN "CPCONFIG"."NOFILE_LIMIT" IS '可选，无文件告警时限（秒）';
   COMMENT ON COLUMN "CPCONFIG"."FILE_ANALYZER" IS '可选，话单文件分析器';
   COMMENT ON COLUMN "CPCONFIG"."SEQUENCE_CONTROL" IS '可选，序号控制，0=无  1=严格序号采集';
   COMMENT ON COLUMN "CPCONFIG"."SEQUENCE_SCOPE" IS '可选，序号范围，如0001-9999';
   COMMENT ON COLUMN "CPCONFIG"."SEQUENCE_SYNC" IS '可选，是否向容灾系统同步序号';
   COMMENT ON COLUMN "CPCONFIG"."WARN_MODE" IS '可选，告警模式，每位控制一种场景';
   COMMENT ON COLUMN "CPCONFIG"."RECORD_SIZE" IS '可选，记录大小，整个文件的大小是其整数倍数';
   COMMENT ON COLUMN "CPCONFIG"."FTP_TIMEOUT" IS '可选，FTP 操作超时时限（秒）';
   COMMENT ON COLUMN "CPCONFIG"."FTP_RESUME" IS '可选，FTP 断点续传标志';
   COMMENT ON COLUMN "CPCONFIG"."FTP_PASSIVE" IS '可选，FTP 被动模式标志';
   COMMENT ON COLUMN "CPCONFIG"."SIZE_COL" IS '可选，指定文件大小位于目录列表的第几列；
对于部分不能直接获取文件大小的服务器，必须指定；
windows服务器，通常为5
';
   COMMENT ON COLUMN "CPCONFIG"."EXTRACOPY" IS '可选，额外保存几份';
   COMMENT ON COLUMN "CPCONFIG"."STATUS" IS '是否在用';
   COMMENT ON COLUMN "CPCONFIG"."LOGTIME" IS '录入时间，默认值SYSDATE';





